import{_ as s,C as t,o as h,c,j as a,a as i,E as n,a3 as m}from"./chunks/framework.CVjg771q.js";const P=JSON.parse('{"title":"帛书第1章 论德","description":"帛书德篇第1章 · 论德（通行本第38章）","frontmatter":{"title":"帛书第1章 论德","description":"帛书德篇第1章 · 论德（通行本第38章）","category":"guide","aliases":["帛书第1章","马王堆老子1","通行本第38章"],"source":["马王堆汉墓帛书《老子》甲本"]},"headers":[],"relativePath":"daoism/texts/dao-de-jing-boshu/chapter-01.md","filePath":"daoism/texts/dao-de-jing-boshu/chapter-01.md","lastUpdated":1778755688000}'),u={name:"daoism/texts/dao-de-jing-boshu/chapter-01.md"};function p(x,e,g,b,_,f){const o=t("DaoReadingPrelude"),r=t("DaoOriginalReading"),d=t("DaoLineGuide"),l=t("DaoKeywordCards");return h(),c("div",null,[e[0]||(e[0]=a("h1",{id:"帛书老子第1章",tabindex:"-1"},[i("帛书老子第1章 "),a("a",{class:"header-anchor",href:"#帛书老子第1章","aria-label":'Permalink to "帛书老子第1章"'},"​")],-1)),n(o,{title:"第1章 论德",summary:"本章出自马王堆帛书《老子》甲本德篇，对应通行本第38章。帛书本德篇在前、道篇在后，文字多作「亓」「恒」「邦」等古字，反映了更早的写本面貌。",points:[{label:"底本",text:"马王堆帛书甲本 · 德篇第1章"},{label:"对照",text:"通行本第38章，注意篇序与文字差异"},{label:"读法",text:"初读先顺原文；再读可对照通行本逐句比对异同。"}],hint:'帛书甲本是现存最早的《老子》完整写本之一。文中括号注如「泊（薄）」表示帛书作"泊"，校读为"薄"。'}),e[1]||(e[1]=a("h2",{id:"【原典层】原文",tabindex:"-1"},[i("【原典层】原文 "),a("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),n(r,{paragraphs:["上德不德 是以有德","下德不失德 是以无德","上德无为 而无以为也","上仁为之 而无以为也","上义为之 而有以为也","上礼为之 而莫之应也","则攘臂而扔之","故失道而后德 失德而后仁","失仁而后义 失义而后礼","夫礼者 忠信之泊也 而乱之首也","前识者 道之华也 而愚之首也","是以大丈夫居亓厚而不居亓泊","居亓实而不居亓华 故去彼取此"]}),n(d,{lines:[{text:"上德不德 是以有德",tone:"起",guide:"最高的德，不自居为德——不标榜、不炫耀，反而因此拥有了真正的德。全章总纲。"},{text:"下德不失德 是以无德",tone:"承",guide:"次一等的德，时刻执着于「不失德」——越是刻意守住德的名分，反而失去了德的实质。"},{text:"上德无为 而无以为也",tone:"法",guide:"上德之人以无为行事，且不觉得自己在「做」什么——连无为的意识都不执着。"},{text:"上仁为之 而无以为也",tone:"法",guide:"上等的仁爱虽有所作为，但也不刻意标榜，出于自然而非计算。"},{text:"上义为之 而有以为也",tone:"法",guide:"上等的义则有明确的作为意识——义已进入「应当如此」的价值判断层面。"},{text:"上礼为之 而莫之应也",tone:"法",guide:"到了礼的层面，有明确的规范仪式——但人心已不再自然响应，礼是外在的强制。"},{text:"则攘臂而扔之",tone:"喻",guide:"只能卷起袖子强行拉扯——当内在的感通消失后，外在的规范就变成了强制。"},{text:"故失道而后德 失德而后仁",tone:"转",guide:"老子的退化史观：道丧失才有德的标举，德丧失才有仁的提倡——每退一步，离源头就远一步。"},{text:"失仁而后义 失义而后礼",tone:"转",guide:"仁丧失才有义的强调，义丧失才有礼的强制——礼的出现，恰说明内在秩序的崩坏。"},{text:"夫礼者 忠信之泊也 而乱之首也",tone:"断",guide:"礼，是忠信稀薄之后的产物，且是一切混乱的开端。帛书「泊」通「薄」——不是否定礼本身，而是指出当礼成为唯一维系手段时，内在道德已空。"},{text:"前识者 道之华也 而愚之首也",tone:"断",guide:"「前识」——人为的先见之明——只是道的浮华外表，是一切愚昧的开端。反对的不是智慧，而是脱离道之根基的自作聪明。"},{text:"是以大丈夫居亓厚而不居亓泊",tone:"法",guide:"大丈夫选择站在厚实之处（道与德的根基），不站在浅薄之处（礼的表层）。帛书「亓」通「其」。"},{text:"居亓实而不居亓华 故去彼取此",tone:"收",guide:"站在真实根基上，不追求浮华外表。舍弃浅薄的（礼、前识），选取厚实的（道、德）——明确选择源头。"}]}),e[2]||(e[2]=a("h2",{id:"【原典层】字词释义",tabindex:"-1"},[i("【原典层】字词释义 "),a("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),n(l,{items:[{term:"德",pinyin:["dé"],meaning:"道的体现。上德即不执着于德之名的德，下德即执着于不失德之名的德。帛书以德篇开篇。",context:"本章以「上德不德」发端，展开德→仁→义→礼的退化序列。"},{term:"泊",pinyin:["bó"],meaning:"通「薄」，淡薄、稀薄。忠信之泊——忠信变得稀薄，只剩下外在形式。",context:"帛书作「泊」，通行本校读为「薄」。"},{term:"攘臂",pinyin:["rǎng","bì"],meaning:"卷起袖子、伸出胳膊。形容强行拉扯、强迫他人服从。",context:"当礼失去内在感通，就只能靠外在强制——攘臂而扔之。"},{term:"前识",pinyin:["qián","shí"],meaning:"预先的智识、人为的先见之明。脱离道的根基而自作聪明的认知。",context:"老子称之「道之华而愚之首」——看似聪明，实为愚昧的开端。"},{term:"亓",pinyin:["qí"],meaning:"帛书古字，通「其」。全书通用，是战国至汉初的常用写法。",context:"通行本全作「其」。一字之差，可见帛书用字之古。"},{term:"仁",pinyin:["rén"],meaning:"仁爱。在老子序列中，仁是德退化之后的产物——失德而后仁。仁虽好，已不如德之自然。",context:"上仁为之而无以为——上等的仁爱有所作为但不刻意。"},{term:"义",pinyin:["yì"],meaning:"道义、应当。比仁更进一步退化——失仁而后义。义有明确的「应该」判断。",context:"上义为之而有以为——上等的义有明确的作为意识。"},{term:"礼",pinyin:["lǐ"],meaning:"礼仪规范。在老子序列中是退化链条的最末端——失义而后礼。礼是外在的强制。",context:"夫礼者，忠信之泊也，而乱之首也——礼的出现，说明内在道德已经空了。"}]}),e[3]||(e[3]=m("",13))])}const y=s(u,[["render",p]]);export{P as __pageData,y as default};
